import 'package:bookly/Feature/Books/presentation/manager/similar_books_cubit.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../../../Core/Models/book_model.dart';import '../widgets/Information Books/custom_book_details_appbar_1.dart';import '../widgets/Information Books/information_books_builder_2.dart';import '../widgets/SimilarBooks/similar_books_builder.dart';class ViewInformationBook extends StatefulWidget {  const ViewInformationBook({super.key, required this.item});  final BookModel item;  @override  State<ViewInformationBook> createState() => _ViewInformationBookState();}class _ViewInformationBookState extends State<ViewInformationBook> {  @override  void initState() {    super.initState();    BlocProvider.of<SimilarBooksCubit>(context)        .fetchSimilarBooks(category: widget.item.volumeInfo!.categories![0]);  }  @override  Widget build(BuildContext context) {    return Scaffold(      body: SafeArea(          child: Column(        children: [          const CustomBookDetailsAppbar(),          DetailsTheBook(            item: widget.item,          ),          const SimilarBooks()        ],      )),    );  }}